import time

class Cache:
    def __init__(self, max_size=100, default_ttl=300):
        self.store = {}
        self.max_size = max_size
        self.default_ttl = default_ttl
        self.hits = 0
        self.misses = 0

    def get(self, key):
        entry = self.store.get(key)
        if entry is None:
            self.misses += 1
            return None
        if entry['expires'] < time.time():
            del self.store[key]
            self.misses += 1
            return None
        self.hits += 1
        return entry['value']

    def set(self, key, value, ttl=None):
        if len(self.store) >= self.max_size:
            self._evict()
        ttl = ttl or self.default_ttl
        self.store[key] = {
            'value': value,
            'expires': time.time() + ttl,
            'created': time.time()
        }

    def _evict(self):
        oldest_key = None
        oldest_time = float('inf')
        for key, entry in self.store.items():
            if entry['created'] < oldest_time:
                oldest_time = entry['created']
                oldest_key = key
        if oldest_key:
            del self.store[oldest_key]

    def stats(self):
        total = self.hits + self.misses
        return {
            'hits': self.hits,
            'misses': self.misses,
            'hit_rate': self.hits / total if total else 0,
            'size': len(self.store)
        }

