class HttpClient:
    def __init__(self, cache=None):
        self.cache = cache or Cache()
        self.default_headers = {'Content-Type': 'application/json'}

    def _build_headers(self, extra_headers=None):
        headers = dict(self.default_headers)
        if extra_headers:
            headers.update(extra_headers)
        return headers

    def get(self, url, headers=None, use_cache=True):
        if use_cache:
            cached = self.cache.get(url)
            if cached is not None:
                return cached
        final_headers = self._build_headers(headers)
        response = self._make_request('GET', url, final_headers)
        if use_cache and response['status'] == 200:
            self.cache.set(url, response)
        return response

    def post(self, url, data, headers=None):
        final_headers = self._build_headers(headers)
        response = self._make_request('POST', url, final_headers, data)
        return response

